export interface GuildBenefit {
    type: string;
    value: number;
    description: string;
}

export interface GuildLevel {
    points: number;
    name: string;
    perks: GuildPerk[];
}

export interface GuildPerk {
    type: string;
    id?: string;
    value?: number;
}

export interface GuildData {
    id: string;
    name: string;
    icon: string;
    description: string;
    benefits: GuildBenefit[];
    levels: GuildLevel[];
}

export class GuildSystem {
    private isInitialized: boolean = false;
    private currentGuild: string | null = null;
    private guildData: Map<string, GuildData> = new Map();
    private guildRank: number = 0;
    private guildPoints: number = 0;

    constructor() {
        this.isInitialized = false;
        this.currentGuild = null;
        this.guildRank = 0;
        this.guildPoints = 0;
    }

    async init(): Promise<void> {
        this.loadGuildData();
        this.loadPlayerGuild();
        this.isInitialized = true;
        console.log('[GuildSystem] 公会系统初始化完成');
    }

    private loadGuildData(): void {
        this.registerGuild({
            id: 'guild_warriors',
            name: '战士公会',
            icon: '⚔️',
            description: '战士的聚集地，专注于战斗技巧和武器精通',
            benefits: [
                { type: 'atk', value: 5, description: '攻击力 +5' },
                { type: 'hp', value: 20, description: '生命上限 +20' }
            ],
            levels: [
                { points: 0, name: '新手战士', perks: [] },
                { points: 100, name: '熟练战士', perks: [{ type: 'skill_unlock', id: 'warrior_special' }] },
                { points: 500, name: '精英战士', perks: [{ type: 'bonus_damage', value: 0.1 }] },
                { points: 2000, name: '传奇战士', perks: [{ type: 'skill_unlock', id: 'warrior_ultimate' }] }
            ]
        });

        this.registerGuild({
            id: 'guild_mages',
            name: '法师公会',
            icon: '🔮',
            description: '魔法师的殿堂，专注于奥术研究和法术威力',
            benefits: [
                { type: 'mag', value: 8, description: '魔法攻击 +8' },
                { type: 'mp', value: 30, description: '魔法上限 +30' }
            ],
            levels: [
                { points: 0, name: '学徒法师', perks: [] },
                { points: 100, name: '正式法师', perks: [{ type: 'skill_unlock', id: 'mage_special' }] },
                { points: 500, name: '高阶法师', perks: [{ type: 'mana_efficiency', value: 0.15 }] },
                { points: 2000, name: '大魔导师', perks: [{ type: 'skill_unlock', id: 'mage_ultimate' }] }
            ]
        });

        this.registerGuild({
            id: 'guild_rogues',
            name: '盗贼公会',
            icon: '🗡️',
            description: '暗影中的组织，专注于潜行、暗杀和偷盗',
            benefits: [
                { type: 'crit', value: 3, description: '暴击率 +3%' },
                { type: 'spd', value: 5, description: '速度 +5' }
            ],
            levels: [
                { points: 0, name: '见习盗贼', perks: [] },
                { points: 100, name: '正式盗贼', perks: [{ type: 'skill_unlock', id: 'rogue_special' }] },
                { points: 500, name: '精英盗贼', perks: [{ type: 'critical_bonus', value: 0.2 }] },
                { points: 2000, name: '暗影大师', perks: [{ type: 'skill_unlock', id: 'rogue_ultimate' }] }
            ]
        });

        this.registerGuild({
            id: 'guild_merchants',
            name: '商人公会',
            icon: '💰',
            description: '商业联盟，专注于贸易、谈判和财富积累',
            benefits: [
                { type: 'gold_bonus', value: 0.1, description: '金币获取 +10%' },
                { type: 'discount', value: 0.1, description: '商店折扣 10%' }
            ],
            levels: [
                { points: 0, name: '小商贩', perks: [] },
                { points: 100, name: '商人', perks: [{ type: 'shop_unlock', id: 'merchant_special' }] },
                { points: 500, name: '大商人', perks: [{ type: 'discount', value: 0.15 }] },
                { points: 2000, name: '贸易大师', perks: [{ type: 'gold_bonus', value: 0.2 }] }
            ]
        });

        this.registerGuild({
            id: 'guild_craftsmen',
            name: '工匠公会',
            icon: '🔨',
            description: '工匠的家园，专注于制作、锻造和工艺提升',
            benefits: [
                { type: 'crafting_exp', value: 0.2, description: '制作经验 +20%' },
                { type: 'crafting_bonus', value: 0.1, description: '制作成功率 +10%' }
            ],
            levels: [
                { points: 0, name: '学徒工匠', perks: [] },
                { points: 100, name: '工匠', perks: [{ type: 'recipe_unlock', id: 'basic' }] },
                { points: 500, name: '高级工匠', perks: [{ type: 'recipe_unlock', id: 'advanced' }] },
                { points: 2000, name: '大师工匠', perks: [{ type: 'recipe_unlock', id: 'legendary' }] }
            ]
        });

        this.registerGuild({
            id: 'guild_adventurers',
            name: '冒险者公会',
            icon: '🗺️',
            description: '冒险者的聚集地，专注于探索和完成任务',
            benefits: [
                { type: 'exp_bonus', value: 0.1, description: '经验获取 +10%' },
                { type: 'quest_reward', value: 0.15, description: '任务奖励 +15%' }
            ],
            levels: [
                { points: 0, name: '见习冒险者', perks: [] },
                { points: 100, name: '冒险者', perks: [{ type: 'quest_unlock', id: 'daily' }] },
                { points: 500, name: '精英冒险者', perks: [{ type: 'map_unlock', id: 'secret_area' }] },
                { points: 2000, name: '传奇冒险者', perks: [{ type: 'title_unlock', id: 'world_explorer' }] }
            ]
        });
    }

    private registerGuild(guild: GuildData): void {
        this.guildData.set(guild.id, guild);
    }

    joinGuild(guildId: string): boolean {
        const guild = this.guildData.get(guildId);
        if (!guild) {
            const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
            win.game?.showNotification?.('公会不存在', 'error');
            return false;
        }

        if (this.currentGuild === guildId) {
            const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
            win.game?.showNotification?.('你已经在这个公会了', 'warning');
            return false;
        }

        if (this.currentGuild) {
            const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
            win.game?.showNotification?.('退出当前公会才能加入新公会', 'warning');
            return false;
        }

        this.currentGuild = guildId;
        this.guildRank = 0;
        this.guildPoints = 0;

        this.applyGuildBenefits(guild);

        const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void }; audioSystem?: { playSound?: (sound: string) => void } };
        win.game?.showNotification?.(`成功加入 ${guild.name}！`, 'success');
        win.audioSystem?.playSound?.('levelUp');

        this.savePlayerGuild();
        return true;
    }

    leaveGuild(): boolean {
        if (!this.currentGuild) {
            const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
            win.game?.showNotification?.('你还没有加入公会', 'warning');
            return false;
        }

        const guild = this.guildData.get(this.currentGuild);
        if (guild) {
            this.removeGuildBenefits(guild);
        }

        this.currentGuild = null;
        this.guildRank = 0;
        this.guildPoints = 0;

        const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
        win.game?.showNotification?.(`已退出 ${guild?.name}`, 'info');
        this.savePlayerGuild();
        return true;
    }

    private applyGuildBenefits(guild: GuildData): void {
        const win = window as unknown as { game?: { player?: { atk: number; mag: number; maxHp: number; hp: number; maxMp: number; mp: number } } };
        const player = win.game?.player;
        if (!player) return;

        for (const benefit of guild.benefits) {
            switch (benefit.type) {
                case 'atk':
                    player.atk = (player.atk || 0) + benefit.value;
                    break;
                case 'mag':
                    player.mag = (player.mag || 0) + benefit.value;
                    break;
                case 'hp':
                    player.maxHp = (player.maxHp || 100) + benefit.value;
                    player.hp = (player.hp || 100) + benefit.value;
                    break;
                case 'mp':
                    player.maxMp = (player.maxMp || 50) + benefit.value;
                    player.mp = (player.mp || 50) + benefit.value;
                    break;
            }
        }
    }

    private removeGuildBenefits(guild: GuildData): void {
        const win = window as unknown as { game?: { player?: { atk: number; mag: number; maxHp: number; hp: number; maxMp: number; mp: number } } };
        const player = win.game?.player;
        if (!player) return;

        for (const benefit of guild.benefits) {
            switch (benefit.type) {
                case 'atk':
                    player.atk = Math.max(0, (player.atk || 0) - benefit.value);
                    break;
                case 'mag':
                    player.mag = Math.max(0, (player.mag || 0) - benefit.value);
                    break;
                case 'hp':
                    player.maxHp = Math.max(100, (player.maxHp || 100) - benefit.value);
                    player.hp = Math.min(player.maxHp, player.hp || 100);
                    break;
                case 'mp':
                    player.maxMp = Math.max(50, (player.maxMp || 50) - benefit.value);
                    player.mp = Math.min(player.maxMp, player.mp || 50);
                    break;
            }
        }
    }

    gainPoints(amount: number): void {
        if (!this.currentGuild) return;

        this.guildPoints += amount;
        this.checkRankUp();

        this.savePlayerGuild();
    }

    private checkRankUp(): void {
        const guild = this.currentGuild ? this.guildData.get(this.currentGuild) : null;
        if (!guild) return;

        const nextRank = guild.levels[this.guildRank + 1];
        if (nextRank && this.guildPoints >= nextRank.points) {
            this.guildRank++;

            this.applyRankPerks(nextRank.perks);

            const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void }; audioSystem?: { playSound?: (sound: string) => void } };
            win.game?.showNotification?.(`公会等级提升：${nextRank.name}！`, 'success');
            win.audioSystem?.playSound?.('levelUp');
        }
    }

    private applyRankPerks(perks: GuildPerk[]): void {
        const win = window as unknown as { game?: { player?: { skills?: string[]; unlockedContent?: string[] } } };
        const player = win.game?.player;

        for (const perk of perks) {
            switch (perk.type) {
                case 'skill_unlock':
                    if (player?.skills) {
                        player.skills.push(perk.id || '');
                    }
                    break;
                case 'recipe_unlock':
                case 'shop_unlock':
                case 'quest_unlock':
                case 'map_unlock':
                case 'title_unlock':
                    if (player) {
                        if (!player.unlockedContent) {
                            player.unlockedContent = [];
                        }
                        player.unlockedContent.push(perk.id || '');
                    }
                    break;
            }
        }
    }

    getGuildBenefit(type: string): number {
        if (!this.currentGuild) return 0;

        const guild = this.guildData.get(this.currentGuild);
        if (!guild) return 0;
        
        const benefit = guild.benefits.find(b => b.type === type);
        return benefit ? benefit.value : 0;
    }

    getCurrentGuild(): GuildData | null {
        return this.currentGuild ? this.guildData.get(this.currentGuild) || null : null;
    }

    getAllGuilds(): GuildData[] {
        return Array.from(this.guildData.values());
    }

    getCurrentRank(): GuildLevel | null {
        if (!this.currentGuild) return null;

        const guild = this.guildData.get(this.currentGuild);
        return guild ? guild.levels[this.guildRank] : null;
    }

    getNextRank(): GuildLevel | null {
        if (!this.currentGuild) return null;

        const guild = this.guildData.get(this.currentGuild);
        return guild ? guild.levels[this.guildRank + 1] || null : null;
    }

    renderGuildList(): void {
        const container = document.getElementById('guild-list');
        if (!container) return;

        container.innerHTML = '';

        for (const guild of this.guildData.values()) {
            const guildElement = document.createElement('div');
            guildElement.className = 'guild-card';
            const isCurrent = this.currentGuild === guild.id;

            guildElement.innerHTML = `
                <div class="guild-icon">${guild.icon}</div>
                <div class="guild-info">
                    <div class="guild-name">${guild.name}</div>
                    <div class="guild-description">${guild.description}</div>
                    <div class="guild-benefits">
                        ${guild.benefits.map(b => `<span>${b.description}</span>`).join(' | ')}
                    </div>
                </div>
                <div class="guild-actions">
                    ${isCurrent ? `
                        <span class="current-badge">当前公会</span>
                        <button class="btn btn-danger" onclick="guildSystem.leaveGuild()">退出</button>
                    ` : `
                        <button class="btn btn-primary" onclick="guildSystem.joinGuild('${guild.id}')">加入</button>
                    `}
                </div>
            `;

            container.appendChild(guildElement);
        }
    }

    private loadPlayerGuild(): void {
        const saved = localStorage.getItem('tavern_guild');
        if (saved) {
            try {
                const data = JSON.parse(saved);
                this.currentGuild = data.guildId;
                this.guildRank = data.rank || 0;
                this.guildPoints = data.points || 0;
            } catch (error) {
                console.error('[GuildSystem] Failed to load guild data:', error);
            }
        }
    }

    private savePlayerGuild(): void {
        const data = {
            guildId: this.currentGuild,
            rank: this.guildRank,
            points: this.guildPoints
        };
        localStorage.setItem('tavern_guild', JSON.stringify(data));
    }
}

export default GuildSystem;
